// ═══════════════════════════════════════════════════════════════
// SÁNATE WhatsApp AI Bot — n8n Code Node v2.0
// Maneja: texto, audio (Whisper), imagen (GPT-4o Vision)
// ═══════════════════════════════════════════════════════════════

const item = $input.first();
const data = item.json.body || item.json;

const {
  chatId,
  messageType = 'text',
  text = '',
  audioUrl = '',
  imageUrl = '',
  clientName = 'Cliente',
  systemPrompt = '',
  openaiKey = '',
  history = [],
  backendUrl = '',
  backendSecret = ''
} = data;

// Validar datos mínimos
if (!chatId) {
  return [{ json: { ok: false, error: 'chatId requerido' } }];
}
if (!openaiKey) {
  return [{ json: { ok: false, error: 'openaiKey requerido' } }];
}

// ── HELPERS ──────────────────────────────────────────────────
const OAI = 'https://api.openai.com/v1';
const authHeader = `Bearer ${openaiKey}`;

async function openaiChat(messages, model = 'gpt-4o-mini') {
  const res = await fetch(`${OAI}/chat/completions`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': authHeader },
    body: JSON.stringify({ model, messages, max_tokens: 1000, temperature: 0.7 })
  });
  const d = await res.json();
  if (!res.ok) throw new Error(d.error?.message || 'OpenAI error');
  return d.choices?.[0]?.message?.content || '';
}

// ── SISTEMA BASE ──────────────────────────────────────────────
const baseSystem = systemPrompt ||
  `Eres el asistente de ventas de Sánate. Responde de forma cálida, natural y enfocada en cerrar la venta.
` +
  `FORMATO: Divide tu respuesta en 2-4 partes cortas separadas por ||||
` +
  `REGLAS: Siempre diagnostica antes de dar precios. Termina con pregunta de cierre.`;

// ── PASO 1: PROCESAR AUDIO SI ES NECESARIO ───────────────────
let finalText = text;
let transcription = null;

if (messageType === 'audio' && audioUrl) {
  try {
    // Descargar el audio
    const audioResp = await fetch(audioUrl, {
      headers: backendSecret ? { 'x-secret': backendSecret } : {}
    });
    if (!audioResp.ok) throw new Error(`Audio download failed: ${audioResp.status}`);

    const audioBuffer = await audioResp.arrayBuffer();
    const audioBlob = new Blob([audioBuffer], { type: 'audio/ogg' });

    // Transcribir con Whisper
    const formData = new FormData();
    formData.append('file', audioBlob, 'audio.ogg');
    formData.append('model', 'whisper-1');
    formData.append('language', 'es');

    const whisperRes = await fetch(`${OAI}/audio/transcriptions`, {
      method: 'POST',
      headers: { 'Authorization': authHeader },
      body: formData
    });
    const whisperData = await whisperRes.json();
    transcription = whisperData.text || '';
    finalText = transcription || '[Nota de voz no transcrita]';
  } catch (e) {
    finalText = '[Nota de voz — error al transcribir]';
  }
}

// ── PASO 2: CONSTRUIR MENSAJES PARA IA ───────────────────────
const messages = [
  { role: 'system', content: baseSystem },
  ...((history || []).slice(-10)),
];

if (messageType === 'image' && imageUrl) {
  // Visión: analizar imagen
  const imagePrompt = finalText || 'El cliente envió una imagen. Analízala y responde de forma relevante.';
  messages.push({
    role: 'user',
    content: [
      { type: 'text', text: imagePrompt },
      { type: 'image_url', image_url: { url: imageUrl, detail: 'low' } }
    ]
  });
} else {
  messages.push({ role: 'user', content: finalText || '[mensaje vacío]' });
}

// ── PASO 3: LLAMAR A OpenAI ───────────────────────────────────
const model = messageType === 'image' ? 'gpt-4o' : 'gpt-4o-mini';
let reply = '';
try {
  reply = await openaiChat(messages, model);
} catch (e) {
  return [{ json: { ok: false, error: e.message } }];
}

// ── PASO 4: ENVIAR VIA BACKEND SI HAY URL PÚBLICA ────────────
let sent = false;
const isPublicBackend = backendUrl &&
  !backendUrl.includes('localhost') &&
  !backendUrl.includes('127.0.0.1') &&
  backendUrl.startsWith('http');

if (isPublicBackend && reply) {
  const parts = reply.split('||||').map(p => p.trim()).filter(Boolean);
  for (const part of parts) {
    try {
      const fd = new FormData();
      fd.append('text', part);
      await fetch(`${backendUrl}/chats/${encodeURIComponent(chatId)}/send`, {
        method: 'POST',
        headers: backendSecret ? { 'x-secret': backendSecret } : {},
        body: fd
      });
      // Pequeña pausa entre mensajes
      await new Promise(r => setTimeout(r, 600));
    } catch (e) {
      // Continúa con el siguiente part
    }
  }
  sent = true;
}

// ── RESPUESTA AL FRONTEND ─────────────────────────────────────
return [{
  json: {
    ok: true,
    reply,
    sent,
    transcription: transcription || undefined,
    model,
    parts: reply.split('||||').map(p => p.trim()).filter(Boolean)
  }
}];
